  "code": "python
def topological_sort(dependencies):
    graph = {}
    in_degree = {}
    top_sorted = []

    # Build the graph and calculate in-degrees
    for task, prereqs in dependencies.items():
        graph[task] = prereqs.copy()
        for prereq in prereqs:
            if prereq not in in_degree:
                in_degree[prereq] = 0
            in_degree[prereq] += 1

    # Use DFS to topologically sort tasks
    def dfs(node):
        if node in visited or node not in graph:
            return False
        visited.add(node)
        for prereq in graph[node]:
            if not dfs(prereq):
                return False
        top_sorted.append(node)
        return True

    visited = set()

    # Perform DFS on each unvisited node
    for task in graph:
        if task not in visited and not dfs(task):
            raise ValueError('Cycle detected in dependency graph')

    return top_sorted",
