    "task_summary": "Compares semantic version strings and returns -1, 0, or 1",
    "approach": "Iterates through each part of the version string in descending order and compares corresponding parts.",
    "code": "def compare_versions(version1, version2):
    # Split the version strings into lists of numbers
    version1_parts = list(map(int, version1.split('.')))
    version2_parts = list(map(int, version2.split('.'))

    # Iterate through each part of the version string in descending order and compare corresponding parts
    for i in range(max(len(version1_parts), len(version2_parts)), 0, -1):
        if i > len(version1_parts):  # If there are more parts in version2 than version1, version2 is larger
            return 1
        elif i > len(version2_parts):  # If there are more parts in version1 than version2, version1 is smaller
            return -1
        else:
            if version1_parts[i-1] < version2_parts[i-1]:
                return -1
            elif version1_parts[i-1] > version2_parts[i-1]:
                return 1

    # If all parts are the same, versions are equal
    return 0",
