{
  "task_summary": "Implement an LRU cache in Python",
  "approach": "Use a dictionary for caching and a doubly linked list to maintain order of access.",
  "code": "```python
class LRUCache:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.cache = {}
        self.head = Node(None)
        self.tail = Node(None)
        self.head.next = self.tail
        self.tail.prev = self.head

def insert_node(node):
    node.next = self.head.next
    node.prev = self.head
    self.head.next.prev = node
    self.head.next = node

def delete_node(node):
    prev_node = node.prev
    next_node = node.next
    prev_node.next = next_node
    next_node.prev = prev_node

class Node:
    def __init__(self, key=None):
        self.key = key
        self.value = None
        self.prev = None
        self.next = None
```
```python
def get(self, key: int) -> int:
    if key in self.cache:
        node = self.cache[key]
        delete_node(node)
        insert_node(node)
        return node.value
    else:
        return -1

def put(self, key: int, value: int) -> None:
    if key in self.cache:
        node = self.cache[key]
        node.value = value
        delete_node(node)
        insert_node(node)
    else:
        new_node = Node(key)
        new_node.value = value
        self.cache[key] = new_node
        if len(self.cache) > self.capacity:
            last_node = self.tail.prev
            del self.cache[last_node.key]
            delete_node(last_node)

