  "code": "```python
def evaluate_expression(expression):
    def precedence(op):
        if op in ('+', '-'): return 1
        elif op in ('*', '/'): return 2
        else: return -1

def is_parentheses(c):
    return c == '(' or c == ')'

def infix_to_postfix(expression):
    stack = []
    output = ''
    for char in expression:
        if char.isdigit():
            output += char
        elif is_parentheses(char):
            if char == '(':
                stack.append(char)
            else:
                while stack and stack[-1] != '(':
                    output += stack.pop() + ' '
                stack.pop()
        else:
            while stack and precedence(stack[-1]) >= precedence(char):
                output += stack.pop() + ' '
            stack.append(char)
    while stack:
        output += stack.pop() + ' '
    return output.strip()

def evaluate_postfix(expression):
    stack = []
    for char in expression.split(' '):
        if char.isdigit():
            stack.append(int(char))
        else:
            b = stack.pop()
            a = stack.pop()
            if char == '+':
                stack.append(a + b)
            elif char == '-':
                stack.append(a - b)
            elif char == '*':
                stack.append(a * b)
            else:
                stack.append(a / b)
    return stack.pop()

