{
  "task_summary": "Compare Two Nested Objects Recursively",
  "approach": "Use Depth-First Search (DFS) for Comparison",
  "code": "function recursiveDiff(obj1, obj2) {
    let added = [];
    let removed = [];
    let changed = [];

    function dfs(key, currentObj, targetObj) {
        if (!currentObj[key]) {
            if (targetObj[key] !== undefined) {
                removed.push([key, targetObj[key]]);
            }
        } else if (!targetObj[key]) {
            if (currentObj[key] !== undefined) {
                added.push([key, currentObj[key]]);
            }
        } else if (typeof currentObj[key] === 'object' && typeof targetObj[key] === 'object') {
            dfs(key, currentObj[key], targetObj[key]);
        } else if (currentObj[key] !== targetObj[key]) {
            changed.push([key, { original: currentObj[key], updated: targetObj[key] }]);
        }
    }

    Object.keys(obj1).forEach(key => dfs(key, obj1, obj2));
    Object.keys(obj2).forEach(key => dfs(key, obj1, obj2));

    return { added, removed, changed };
}",
