        for row in data:
            c.execute(sql, row)
        conn.commit()
        print('Data inserted successfully')
    except Error as e:
        print(e)

def validate_data(conn, sql):
    try:
        c = conn.cursor()
        result = c.execute(sql).fetchall()
        if not result:
            return False
        else:
            return True
    except Error as e:
        print(e)

def migrate_data(source_db_name, target_db_name):
