  "task_summary": "Verify overlapping date ranges between two given strings in Python.",
  "approach": "Convert input strings to datetime objects, considering timezone differences and open-ended ranges.",
  "code": "def check_date_range_overlap(start_str: str, end_str: str) -> bool:
    from datetime import datetime, timedelta
    from pytz import timezone

    try:
        start = datetime.strptime(start_str, '%Y-%m-%dT%H:%M:%SZ')
        end = datetime.strptime(end_str, '%Y-%m-%dT%H:%M:%SZ')
    except ValueError:
        return False

    if start > end:
        return False

    timezone_str = 'UTC'  # Default to UTC for simplicity
    if 'GMT' in start_str or 'GMT' in end_str:
        timezone_str = 'GMT'

    start_tz = timezone(timezone_str)
    end_tz = timezone(timezone_str)

    start_dt = start_tz.localize(start)
    end_dt = end_tz.localize(end)

    if start_dt < end_dt:
        return True
    else:
        return False",
