import datetime

def conflict_report(events):
    conflicts = {}
    missing_attendees = set()
    suspicious_durations = []

    # Sort events by start time for easier comparison
    events.sort(key=lambda x: x['start_time'])

    i = 0
    while i < len(events):
        current_event = events[i]
        start, end = current_event['start_time'], current_event['end_time']
        attendee_count = current_event['attendee_count']

        # Check for overlapping meetings
        if i + 1 < len(events) and events[i + 1]['start_time'] < end:
            conflicts[current_event['event_name']] = {'overlaps': [events[i + 1]['event_name']], 'start': start, 'end': end}

        # Check for missing attendees
        if attendee_count == 0 or attendee_count > len(events[i]['attendees']):
            missing_attendees.add(current_event['event_name'])

        # Check for suspicious duration anomalies
        if (end - start) < 0.25 * (len(events) + 1):
            suspicious_durations.append((current_event['event_name'], end - start))

        i += 1

    return {'conflicts': conflicts, 'missing_attendees': missing_attendees, 'suspicious_durations': suspicious_durations}
