# Log analyzer class
import os
from datetime import datetime

class LogAnalyzer:
    def __init__(self, log_dir):
        self.log_dir = log_dir
        self.errors_by_component = {}
        self.start_times = {}
        self.repeated_errors = {}

    def analyze_logs(self):
        for root, dirs, files in os.walk(self.log_dir):
            for file in files:
                if file.endswith('.log'):
                    log_file = os.path.join(root, file)
                    with open(log_file, 'r') as f:
                        lines = f.readlines()
                        self.process_log(lines, file)

    def process_log(self, lines, filename):
        current_time = datetime.now()
        for line in lines:
            # Parse log line to extract error details
            # Example parsing: 'ComponentX - Error message', 'ComponentY - Another error'
            component, error_message = line.strip().split('-')

            # Group errors by component
            if component not in self.errors_by_component:
                self.errors_by_component[component] = set()
            self.errors_by_component[component].add(error_message)

            # Track start time of the first occurrence for each error in a given component
            if component not in self.start_times or line == lines[0]:
                self.start_times[component] = current_time

            # Detect repeated errors within 1 minute
            if component in self.repeated_errors and self.start_times[component] + datetime.timedelta(minutes=1) > current_time:
                repeated_error = tuple(sorted(self.errors_by_component[component]))
                if repeated_error not in self.repeated_errors or current_time - self.repeated_errors[repeated_error] > datetime.timedelta(seconds=60):
                    self.repeated_errors[repeated_error] = current_time

    def summarize_errors(self):
        for component, errors in self.errors_by_component.items():
            if len(errors) > 1:
                repeated_errors_in_time = [tuple(sorted(self.errors_by_component[component]))]
                for start_time in self.repeated_errors.values() + [None]:
                    if start_time is not None and start_time < current_time - datetime.timedelta(minutes=1):
                        repeated_errors_in_time.append(tuple(sorted(errors)) + (start_time,))
                sample_lines = ['{} - {}'.format(line.strip(), datetime.fromtimestamp(time).strftime('%Y-%m-%d %H:%M:%S')) for time in sorted(repeated_errors_in_time)]
                print(f'Summary of errors from {component}:')
                for line in sample_lines[:5]:  # Display the first five samples
                    print(line)
