  "code": "```typescript
import { PriorityQueue } from 'pqueuejs';

interface Job {
  id: number;
  priority: number;
  task: () => Promise<void>;
  retryLimit: number;
  failureCallback: (error: Error) => void;
}

class JobScheduler {
  private queue = new PriorityQueue<number, Job>({ comparator: (a, b) => a.priority - b.priority });
  private runningJobs: Set<number> = new Set<number>();

  constructor(private maxConcurrency: number) {}

  addJob(job: Job): void {
    this.queue.push(job.id, job);
  }

  async run(): Promise<void> {
    while (this.queue.size() > 0 && this.runningJobs.size() < this.maxConcurrency) {
      const jobId = this.queue.pop() as number;
      const job = this.queue.get(jobId)!;

      try {
        await job.task();
        this.runningJobs.delete(jobId);
      } catch (error) {
        if (job.retryLimit > 0) {
          job.retryLimit -= 1;
          this.addJob(job);
        } else {
          job.failureCallback(error);
        }
      }
    }
  }
}

// Example usage:
const scheduler = new JobScheduler(3);
scheduler.addJob({
  id: 1,
  priority: 2,
  task: async () => {
    await new Promise(resolve => setTimeout(resolve, 500));
    console.log('Task 1 completed');
  },
  retryLimit: 3,
  failureCallback: (error) => console.error(`Failed to complete task 1: ${error.message}`)
});
scheduler.addJob({
  id: 2,
  priority: 1,
  task: async () => {
    await new Promise(resolve => setTimeout(resolve, 300));
    console.log('Task 2 completed');
  },
  retryLimit: 2,
  failureCallback: (error) => console.error(`Failed to complete task 2: ${error.message}`)
});
scheduler.run();
