  "code": "```typescript
import { PriorityQueue } from 'fast-priority-queue';

// Job class with priority, retry limit, and failure callback
export class Job {
  constructor(private priority: number, private retries: number, private callback: () => void) {}

  execute() {
    this.retries--;
    if (this.retries < 0) {
      console.error('Job failed after retries:', this.priority);
      return;
    }
    this.callback();
  }
}

// JobScheduler class to manage the job queue and scheduling
export class JobScheduler {
  private priorityQueue = new PriorityQueue<Job>((a, b) => a.priority - b.priority);
  private runningJobs: Map<number, Job> = new Map<number, Job>();
  private currentTaskCount = 0;

  enqueue(job: Job) {
    this.priorityQueue.push(job);
  }

  start() {
    const executeNextJob = () => {
      if (this.runningJobs.size === 0 && this.priorityQueue.isEmpty()) {
        return;
      }

      const job = this.priorityQueue.dequeue();
      const taskCount = ++this.currentTaskCount;
      console.log(`Executing job ${taskCount} with priority ${job.priority}, retries ${job.retries}.`);

      if (!job.running) {
        job.running = true;
        job.execute().then(() => {
          this.runningJobs.delete(taskCount);
          executeNextJob();
        }).catch(error => {
          console.error(`Error executing job ${taskCount} with priority ${job.priority}.`, error);
          if (job.retries > 0) {
            setTimeout(executeNextJob, Math.pow(2, this.retries)); // exponential backoff
          } else {
            console.error('Job failed after retries:', job.priority);
            this.runningJobs.delete(taskCount);
          }
        });
      }
    };

    executeNextJob();
  }
}

// Example usage
const scheduler = new JobScheduler();
scheduler.enqueue(new Job(3, 2, () => console.log('Executing job 1')));
scheduler.enqueue(new Job(1, 3, () => console.log('Executing job 2')));
scheduler.enqueue(new Job(2, 1, () => console.log('Executing job 3')));
scheduler.start();
