  "task_summary": "Implement a lightweight job scheduler with priorities, retry limits, and failure callbacks.",
  "approach": "Use a priority queue to manage jobs based on their priority. Implement a retry mechanism that retries failed jobs a certain number of times. Use promises for handling asynchronous operations.",
  "code": "```typescript
import { PriorityQueue } from 'minheap-js';

class JobScheduler {
  private jobs: PriorityQueue<{ job: () => void, attemptsLeft: number }>

  constructor() {
    this.jobs = new PriorityQueue<[number, { job: () => void, attemptsLeft: number }]>((a, b) => a[0] - b[0]);
  }

  addJob(job: () => void, priority: number, maxAttempts?: number): void {
    const attemptsLeft = maxAttempts || Infinity;
    this.jobs.push([priority, { job, attemptsLeft }], false);
  }

  run(): Promise<void> {
    return new Promise((resolve) => {
      const jobLoop: () => void = async () => {
        if (this.jobs.length > 0) {
          const [priority, { job, attemptsLeft }] = this.jobs.pop()! as [number, { job: () => void, attemptsLeft: number }];

          try {
            await job();
          } catch (error) {
            if (attemptsLeft > 1) {
              console.error(`Job failed (${job.name}): ${error.message}`, `Retrying in ${3 - attemptsLeft} seconds...`);
              setTimeout(() => jobLoop(), 1000 * (3 - attemptsLeft));
            } else {
              console.error(`Job failed (${job.name}): ${error.message}`);
              this.jobs.push([priority, { job, attemptsLeft: 1 }], false);
            }
          } finally {
            resolve();
          }
        } else if (this.jobs.length === 0) {
          console.log('No jobs to run. Exiting...');
          resolve();
        } else {
          setTimeout(jobLoop, 100); // Continue the loop every second
        }
      };

      jobLoop();
    });
  }
}

const scheduler = new JobScheduler();
scheduler.addJob(() => console.log('Running high-priority job'), 2);
scheduler.addJob(() => console.log('Running low-priority job'), 1);
scheduler.run().catch(console.error);
