class CustomerNormalizer:
    def __init__(self):
        self.corrections = []

    def normalize_record(self, record):
        normalized_record = {}
        for key, value in record.items():
            if key == 'name':
                normalized_record['name'] = self.normalize_name(value)
            elif key == 'email':
                normalized_record['email'] = self.normalize_email(value)
            elif key == 'phone_number':
                normalized_record['phone_number'] = self.normalize_phone_number(value)
            elif key == 'country_code':
                normalized_record['country_code'] = self.normalize_country_code(value)
        self.corrections.append(normalized_record)
        return normalized_record

    def normalize_name(self, name):
        # Normalize name by removing special characters and converting to lowercase
        cleaned_name = ''.join(char.lower() for char in name if char.isalnum() or char.isspace())
        return cleaned_name

    def normalize_email(self, email):
        # Normalize email by removing special characters and converting to lowercase
        cleaned_email = ''.join(char.lower() for char in email if char.isalnum() or char.isspace())
        return cleaned_email

    def normalize_phone_number(self, phone_number):
        # Normalize phone number by removing special characters and converting to lowercase
        cleaned_phone_number = ''.join(char.lower() for char in phone_number if char.isdigit() or char.isspace())
        return cleaned_phone_number

    def normalize_country_code(self, country_code):
        # Normalize country code by removing special characters and converting to lowercase
        cleaned_country_code = ''.join(char.lower() for char in country_code if char.isalnum() or char.isspace())
        return cleaned_country_code

